#include <stdio.h>
#include <stdbool.h>

#define MAX_AP 50

typedef struct {
    char ssid[32];
    int channel;
    int signal_strength;  // in dBm
    bool encrypted;
    char auth_type[20];
} AccessPoint;

// Active Scanning - sends probe requests
void active_scan(AccessPoint ap_list[]) {
    int ap_count = 0;

    // Send probe request on all channels
    for (int channel = 1; channel <= 14; channel++) {
        send_probe_request(channel);

        // Wait for probe responses
        AccessPoint ap;
        while (receive_probe_response(&ap)) {
            if (ap_count < MAX_AP) {
                ap_list[ap_count++] = ap;
            }
        }
    }
}

// Passive Scanning - listens for beacon frames
void passive_scan(AccessPoint ap_list[]) {
    int ap_count = 0;

    // Monitor each channel for beacon frames
    for (int channel = 1; channel <= 14; channel++) {
        set_channel(channel);

        while (timeout_not_reached()) {
            if (beacon_received(&ap_list[ap_count])) {
                ap_count++;
            }
        }
    }
}

// Select best access point based on signal strength
AccessPoint select_best_ap(AccessPoint ap_list[], int count) {
    AccessPoint best = ap_list[0];

    for (int i = 1; i < count; i++) {
        if (ap_list[i].signal_strength > best.signal_strength) {
            best = ap_list[i];
        }
    }
    return best;
}

int main() {
    AccessPoint available_aps[MAX_AP];

    printf("Starting Active Scan...\n");
    active_scan(available_aps);

    AccessPoint best = select_best_ap(available_aps, MAX_AP);
    printf("Connecting to: %s (Signal: %d dBm)\n", 
           best.ssid, best.signal_strength);

    return 0;
}
